class Solution {
    public int numberOfWays(int n, int x, int y) {
        final int MOD = (int) (1e9 + 7);
        int[][] dp = new int[n + 1][x + 1];
        dp[0][0] = 1;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= x; j++) {
                dp[i][j] = (int) ((dp[i][j - 1] + (long) dp[i - 1][j - 1] * j) % MOD);
            }
        }
        int totalWays = (int) ((long) dp[n][x] * pow(y, x, MOD) % MOD);
        return totalWays;
    }

    private int pow(int base, int exponent, int mod) {
        int result = 1;
        while (exponent > 0) {
            if ((exponent & 1) == 1) {
                result = (int) ((long) result * base % mod);
            }
            base = (int) ((long) base * base % mod);
            exponent >>= 1;
        }
        return result;
    }
}
